import { describe, expect, it } from 'vitest';

import {
  buildMeshFederationManifest,
  parseMeshFederationPeers,
  resolveFederatedPeerForModel,
} from './mesh-federation';
import { MESH_MODELS } from './mesh-model-registry';

describe('mesh federation manifest', () => {
  it('parses compact peer declarations', () => {
    const peers = parseMeshFederationPeers(
      'west@https://west.example#qwen3-8b|mistral-7b,https://fallback.example',
    );

    expect(peers).toEqual([
      {
        id: 'west',
        baseUrl: 'https://west.example',
        models: ['qwen3-8b', 'mistral-7b'],
        priority: 100,
        weight: 1,
      },
      {
        id: 'fallback.example',
        baseUrl: 'https://fallback.example',
        models: ['*'],
        priority: 100,
        weight: 1,
      },
    ]);
  });

  it('parses JSON peer declarations with priorities', () => {
    const peers = parseMeshFederationPeers(
      JSON.stringify([
        {
          id: 'primary',
          baseUrl: 'https://primary.example/',
          models: ['gemma4-12b-it'],
          priority: 10,
          weight: 2,
        },
      ]),
    );

    expect(peers).toEqual([
      {
        id: 'primary',
        baseUrl: 'https://primary.example',
        models: ['gemma4-12b-it'],
        priority: 10,
        weight: 2,
      },
    ]);
  });

  it('resolves the best peer for a requested model', () => {
    const peers = parseMeshFederationPeers(
      JSON.stringify([
        {
          id: 'fallback',
          baseUrl: 'https://fallback.example',
          models: ['*'],
          priority: 200,
        },
        { id: 'east', baseUrl: 'https://east.example', models: ['qwen3-8b'], priority: 20 },
        { id: 'west', baseUrl: 'https://west.example', models: ['qwen3-8b'], priority: 10 },
      ]),
    );

    expect(resolveFederatedPeerForModel('qwen3-8b', peers)?.id).toBe('west');
    expect(resolveFederatedPeerForModel('unknown-model', peers)?.id).toBe(
      'fallback',
    );
  });

  it('builds a manifest with local capabilities and declared peers', () => {
    const peers = parseMeshFederationPeers('west@https://west.example#qwen3-8b');
    const manifest = buildMeshFederationManifest({
      meshId: 'local',
      publicUrl: 'https://local.example/',
      loadedModel: 'mistral-7b',
      childReady: true,
      models: MESH_MODELS,
      peers,
      generatedAt: '2026-06-18T00:00:00.000Z',
    });

    expect(manifest.kind).toBe('gnosis-openai-mesh-manifest');
    expect(manifest.publicUrl).toBe('https://local.example');
    expect(manifest.loadedModel).toBe('mistral-7b');
    expect(manifest.peers).toEqual(peers);
    expect(manifest.localModels.some((model) => model.id === 'gemma4-12b-it')).toBe(
      true,
    );
    expect(JSON.stringify(manifest)).not.toContain('knotUrl');
  });
});
